function separate_paren_groups(paren_string) {
  const groups = [];
  let current = '';
  let depth = 0;
  for (const ch of paren_string.replaceAll(' ', '')) {
    if (ch === '(') {
      current += ch;
      ++depth;
    } else if (ch === ')') {
      current += ch;
      --depth;
      if (depth === 0) {
        groups.push(current);
        current = '';
      }
    }
  }
