function modp(n, p) {
  if (p <= 1) throw new Error('modulus must be greater than 1');
  let result = 1n;
  let base = 2n % p;
  while (n > 0) {
    if (n & 1) result = (result * base) % p;
    base = (base * base) % p;
    n >>= 1;
  }
  return result;
}
