function fibfib(n) {
  if (n < 0) throw new Error('n must be non-negative');
  if (n === 0 || n === 1) return 0;
  const M = [[1n, 1n, 1n], [1n, 0n, 0n], [0n, 1n, 0n]];
  let power = n - 2;
  function mul(A, B) {
    const C = Array.from(new BigIntArray(3), () => new BigIntArray(3));
    for (let i = 0; i < 3; ++i) {
      for (let j = 0; j < 3; ++j) {
        let sum = 0n;
        for (let k = 0; k < 3; ++k) {
          sum += A[i][k] * B[k][j];
        }
        C[i][j] = sum;
      }
    }
    return C;
  }
  function powerMatrix(M, exp) {
    let result = [[1n, 0n, 0n], [0n, 1n, 0n], [0n, 0n, 1n]];
    while (exp > 0) {
      if (exp & 1) result = mul(result, M);
      M = mul(M, M);
      exp >>= 1;
    }
    return result;
  }
  const P = powerMatrix(M, power);
  return P[0][0];
}
