function minPath(grid, k) {
    const N = grid.length;
    let x = -1, y = -1;
    for (let i = 0; i < N; ++i) {
        for (let j = 0; j < N; ++j) {
            if (grid[i][j] === 1) {
                x = i;
                y = j;
                break;
            }
        }
        if (x !== -1) break;
    }
    const dirs = [[-1, 0], [1, 0], [0, -1], [0, 1]];
    const path = [1];
    for (let step = 2; step <= k; ++step) {
        let minVal = Infinity;
        let nx = -1, ny = -1;
        for (const [dx, dy] of dirs) {
            const nx = x + dx;
            const ny = y + dy;
            if (nx >= 0 && nx < N && ny >= 0 && ny < N) {
                const val = grid[nx][ny];
                if (val < minVal) {
                    minVal = val;
                    nx = nx;
                    ny = ny;
                }
            }
        }
        path.push(minVal);
        x = nx;
        y = ny;
    }
    return path;
}
