  function get(k) {
    if (k <= 0) return undefined;
    if (memo.has(k)) return memo.get(k);
    let res;
    if (k % 2 === 0) {
      res = 1 + k / 2;
    } else {
      const a = get(k - 1);
      const b = get(k - 2);
      const c = get(k + 1);
      res = a + b + c;
    }
    memo.set(k, res);
    return res;
  }
  if (n >= 1) get(1);
  if (n >= 2) get(2);
  const limit = n + 1;
  const result = [];
  for (let i = 1; i <= limit; i++) {
    result.push(get(i));
  }
  return result;
}
