function do_algebra(operator, operand) {
    const nums = operand.map(Number);
    let expr = '';
    for (let i = 0; i < operator.length; i++) {
        const op = operator[i];
        const next = nums[i + 1];
        if (i > 0) expr += ' ';
        expr += nums[i];
        const prec = (op === '**') ? 3 :
                      (op === '*' || op === '/') ? 2 : 1;
        if (i > 0) {
            const prevOp = operator[i - 1];
            let prevPrec;
            switch (prevOp) {
                case '**': prevPrec = 3; break;
                case '*':
                case '/': prevPrec = 2; break;
                case '+':
                case '-': prevPrec = 1; break;
                default: prevPrec = 0;
            }
            if (prec < prevPrec) {
                expr = '(' + expr + ')';
            }
        }
    }
    return eval(expr);
}
