function histogram(test) {
  if (!test) return {};

  const counts = {};
  const letters = test.split(' ');

  for (const letter of letters) {
    counts[letter] = (counts[letter] || 0) + 1;
  }

  const maxCount = Math.max(...Object.values(counts));
  const result = {};

  for (const [letter, count] of Object.entries(counts)) {
    if (count === maxCount) {
      result[letter] = count;
    }
  }

  return result;
}

