            return nums.indexOf(a) - nums.indexOf(b);
        }
        return sumA - sumB;
    });
}

function specialFilter(nums) {
  const oddDigits = new Set([1, 3, 5, 7, 9]);
  let count = 0;
  for (const num of nums) {
    if (num > 10) {
      const absNum = Math.abs(num);
      const firstDigit = Math.floor(Math.abs(Math.log10(absNum))) >= 0 ? Math.abs(Math.floor(absNum / Math.pow(10, Math.floor(Math.log10(absNum))))) : absNum;
      const lastDigit = absNum % 10;
      if (oddDigits.has(firstDigit) && oddDigits.has(lastDigit)) {
        count++;
      }
    }
  }
  return count;
}

function get_max_triples(n) {
  const a = Array.from({ length: n }, (_, i) => (i + 1) * (i + 1) - (i + 1) + 1);
  let count = 0;
  for (let i = 0; i < n - 2; i++) {
    for (let j = i + 1; j < n - 1; j++) {
      for (let k = j + 1; k < n; k++) {
        if ((a[i] + a[j] + a[k]) % 3 === 0) {
          count++;
        }
      }
    }
  }
  return count;
}

function bf(planet1, planet2) {
  const planets = ["Mercury", "Venus", "Earth", "Mars", "Jupiter", "Saturn", "Uranus", "Neptune"];
  const index1 = planets.indexOf(planet1);
  const index2 = planets.indexOf(planet2);
  if (index1 === -1 || index2 === -1 || index1 === index2) {
    return [];
  }
  const start = Math.min(index1, index2);
  const end = Math.max(index1, index2);
  return planets.slice(start + 1, end);
}

function sorted_list_sum(lst) {
    return lst.filter(str => str.length % 2 === 0).sort((a, b) => {
        if (a.length === b.length) {
            return a.localeCompare(b);
        }
        return a.length - b.length;
    });
}

function x_or_y(n, x, y) {
  function isPrime(num) {
    if (num < 2) return false;
    for (let i = 2; i <= Math.sqrt(num); i++) {
      if (num % i === 0) return false;
    }
    return true;
  }

  return isPrime(n) ? x : y;
}

function double_the_difference(lst) {
  return lst.reduce((sum, x) => {
    if (Number.isInteger(x) && x > 0 && x % 2 !== 0) {
      return sum + x * x;
    }
    return sum;
  }, 0);
}

function compare(game, guess) {
  return game.map((score, i) => Math.abs(score - guess[i]));
}

function Strongest_Extension(class_name, extensions) {
    let strongestExtension = extensions[0];
    let maxStrength = 0;

    for (let i = 1; i < extensions.length; i++) {
        const extension = extensions[i];
        const capCount = [...extension].filter(char => char === char.toUpperCase()).length;
        const smCount = [...extension].filter(char => char === char.toLowerCase()).length;
        const strength = capCount - smCount;

        if (strength > maxStrength) {
            strongestExtension = extension;
            maxStrength = strength;
        }
    }

    return `${class_name}.${strongestExtension}`;
}

function cycpattern_check(a, b) {
    if (b.length > a.length) return false;
    for (let i = 0; i < b.length; i++) {
        if (a.includes(b)) return true;
        b = b.charAt(b.length - 1) + b.slice(0, b.length - 1);
    }
    return false;
}

function even_odd_count(num) {
    const absNum = Math.abs(num);
    const strNum = absNum.toString();
    let evenCount = 0;
    let oddCount = 0;
    for (const digit of strNum) {
        if (parseInt(digit) % 2 === 0) {
            evenCount++;
        } else {
            oddCount++;
        }
    }
    return [evenCount, oddCount];
}

function int_to_mini_roman(number) {
  const romanNumerals = [
    { value: 1000, symbol: 'm' },
    { value: 900, symbol: 'cm' },
    { value: 500, symbol: 'd' },
    { value: 400, symbol: 'cd' },
    { value: 100, symbol: 'c' },
    { value: 90, symbol: 'xc' },
    { value: 50, symbol: 'l' },
    { value: 40, symbol: 'xl' },
    { value: 10, symbol: 'x' },
    { value: 9, symbol: 'ix' },
    { value: 5, symbol: 'v' },
    { value: 4, symbol: 'iv' },
    { value: 1, symbol: 'i' },
  ];

  let result = '';
  for (const { value, symbol } of romanNumerals) {
    while (number >= value) {
      result += symbol;
      number -= value;
    }
  }
  return result.toLowerCase();
}

function right_angle_triangle(a, b, c) {
  const sides = [a, b, c].sort((x, y) => x - y);
  return Math.pow(sides[0], 2) + Math.pow(sides[1], 2) === Math.pow(sides[2], 2);
}

function find_max(words) {
  const maxUniqueCount = Math.max(...words.map(word => new Set(word).size));
  const candidates = words.filter(word => new Set(word).size === maxUniqueCount);
  return candidates.sort()[0];
}

function eat(number, need, remaining) {
  const totalEaten = number + Math.min(need, remaining);
  const carrotsLeft = remaining - Math.min(need, remaining);
  return [totalEaten, carrotsLeft];
}

function do_algebra(operator, operand) {
    let result = operand[0];
    for (let i = 0; i < operator.length; i++) {
        const op = operator[i];
        const num = operand[i + 1];
        switch (op) {
            case '+':
                result += num;
                break;
            case '-':
                result -= num;
                break;
            case '*':
                result *= num;
                break;
            case '//':
                result = Math.floor(result / num);
                break;
            case '**':
                result **= num;
                break;
        }
    }
    return result;
}

function solve(s) {
    const hasLetters = /[a-zA-Z]/.test(s);
    if (!hasLetters) {
        return s.split('').reverse().join('');
    }
    return s.split('').map(c => /[a-z]/.test(c) ? c.toUpperCase() : c.toLowerCase()).join('');
}

function string_to_md5(text) {
    if (text === '') {
        return undefined;
    }
    const crypto = require('crypto');
    return crypto.createHash('md5').update(text).digest('hex');
}

function generate_integers(a, b) {
  const start = Math.min(a, b);
  const end = Math.max(a, b);
  const result = [];
  for (let i = start; i <= end; i++) {
    if (i % 2 === 0) {
      result.push(i);
    }
  }
  return result;
}
